const body = $input.first().json.body ?? $input.first().json;
const { material_id, raw_text, title, enabled_personas, enable_av_output, priority_personas, emphasis } = body;

const words = raw_text.split(/\s+/);
const chunkSize = 300;
const chunks = [];
for (let i = 0; i < words.length; i += chunkSize) {
  chunks.push(words.slice(i, i + chunkSize).join(' '));
}
const limited = chunks.slice(0, 5);

const allPersonaSlugs = ['lecture-bestie', 'exam-gremlin', 'problem-grinder', 'doodle-prof', 'meme-lord', 'study-bard'];
const allPostTypes    = ['concept', 'trap', 'example', 'concept', 'example', 'recap'];

// Apply priority_personas ordering from Dify teaching plan:
// priority personas appear first so they generate posts for the most chunks.
const baseActive = Array.isArray(enabled_personas) && enabled_personas.length > 0
  ? enabled_personas.filter(s => allPersonaSlugs.includes(s))
  : allPersonaSlugs;
const prioritySet = Array.isArray(priority_personas) ? new Set(priority_personas) : new Set();
const prioritised = [...baseActive.filter(s => prioritySet.has(s)), ...baseActive.filter(s => !prioritySet.has(s))];
const activePersonas = prioritised;

const imagePrimaryPersonas = new Set(['doodle-prof', 'meme-lord']);
const audioPrimaryPersonas = new Set(['study-bard']);
const otherMediaTypesAV    = ['text', 'slideshow', 'text', 'image'];
const otherMediaTypesNoAV  = ['text', 'image'];

const items = [];
for (let ci = 0; ci < limited.length; ci++) {
  for (let pi = 0; pi < activePersonas.length; pi++) {
    const personaSlug = activePersonas[pi];
    const origIndex   = allPersonaSlugs.indexOf(personaSlug);
    let mediaType;
    if (imagePrimaryPersonas.has(personaSlug)) {
      mediaType = 'image';
    } else if (audioPrimaryPersonas.has(personaSlug)) {
      mediaType = enable_av_output !== false ? 'audio' : 'text';
    } else if (enable_av_output !== false) {
      mediaType = otherMediaTypesAV[ci % otherMediaTypesAV.length];
    } else {
      mediaType = otherMediaTypesNoAV[ci % otherMediaTypesNoAV.length];
    }
    items.push({
      material_id,
      title,
      chunk_text: limited[ci],
      chunk_index: ci,
      persona_slug: personaSlug,
      post_type: allPostTypes[origIndex] ?? 'concept',
      media_type: mediaType,
    });
  }
}

return items.map(item => ({ json: item }));

const allChunks   = $('Split into chunks').all();
const allPersonas = $input.all();
const webhookBody = $('Webhook').first().json.body ?? $('Webhook').first().json;
const emphasis    = webhookBody.emphasis ?? '';

// Persona roster for cross-referencing — lets personas mention each other naturally
const PERSONA_ROSTER = [
  { name: 'Lecture Bestie',  slug: 'lecture-bestie',  specialty: 'plain English explanations and relatable analogies' },
  { name: 'Exam Gremlin',    slug: 'exam-gremlin',    specialty: 'exam traps and common mistakes' },
  { name: 'Problem Grinder', slug: 'problem-grinder', specialty: 'step-by-step worked examples' },
  { name: 'Doodle Prof',     slug: 'doodle-prof',     specialty: 'visual doodle comics' },
  { name: 'Meme Lord',       slug: 'meme-lord',       specialty: 'meme-format explanations' },
  { name: 'Study Bard',      slug: 'study-bard',      specialty: 'songs and lyric-based memory' },
];

const items = [];
for (let i = 0; i < allPersonas.length; i++) {
  const chunk      = allChunks[i].json;
  const personaRaw = allPersonas[i].json;
  const persona    = Array.isArray(personaRaw) ? personaRaw[0] : personaRaw;

  if (!persona || !persona.id) continue;

  // Build roster excluding current persona (for cross-referencing)
  const otherPersonas = PERSONA_ROSTER.filter(p => p.slug !== chunk.persona_slug);
  const rosterText = otherPersonas
    .map(p => `- @${p.name}: ${p.specialty}`)
    .join('\n');

  const emphasisBlock = emphasis
    ? `\n\nThe student's teaching plan highlights this emphasis: "${emphasis}". Lean into this angle — address it naturally in your post.`
    : '';

  const crossRefBlock = `\n\nYou are part of a creator community with these fellow study personas:\n${rosterText}\n\nYou MAY reference them by their @name (e.g. "@Problem Grinder already walked through the steps — I'm here for the WHY") when it naturally enriches your post. Only do this if it feels organic. Never force it.`;

  const userPrompt = `Here is a section of study material titled "${chunk.title}":\n\n${chunk.chunk_text}${emphasisBlock}${crossRefBlock}\n\nGenerate one educational post about the main concept in this section. Return ONLY valid JSON with fields "title" and "body".`;

  items.push({
    json: {
      ...chunk,
      persona_id:    persona.id,
      persona_name:  persona.name,
      system_prompt: persona.system_prompt,
      user_prompt:   userPrompt,
      emphasis,
    }
  });
}

return items;
